#include <stdio.h>
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        char s[4];
        scanf("%s", s);
        if ((s[0] == ':' && s[1] == '-') || (s[0] == ':' && s[1] == '~')) {
            printf("YES\n");
        } else if ((s[0] == ';' && s[1] == '-') || (s[0] == ';' && s[1] == '~')) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

