code.JavaScript:
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let t;
readline.on('line', line => {
    if (i == 0) {
        t = parseInt(line);
        i++;
    } else {
        let s = line;
        if (s == ":-" || s == ":~" || s == ";-" || s == ";~") {
            console.log("YES");
        } else {
            console.log("NO");
        }
        i++;
        if (i > t) {
            readline.close();
        }
    }
});

